import json, glob

# Count the different status combinations
combos = {}
for fp in glob.glob('/local/nick/ai_iree/dataset0206/train/compile_report_worker_*.json'):
    with open(fp) as f:
        data = json.load(f)
    for op_type, shapes in data.items():
        for sk, sd in shapes.items():
            bl = sd['baseline']
            key = (bl['compile'], bl.get('benchmark', 'N/A'))
            combos[key] = combos.get(key, 0) + 1
            for c in sd.get('lowering_configs', []):
                key = (c['compile'], c.get('benchmark', 'N/A'))
                combos[key] = combos.get(key, 0) + 1

for combo, count in sorted(combos.items(), key=lambda x: -x[1]):
    print(f'  compile={combo[0]}, benchmark={combo[1]}: {count}')
"
